void
tlTextureFontChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutLong(version);
        f->PutPString(name);
        f->PutPString(shader);
        f->PutFloat(fontsize);
        f->PutFloat(fontwidth);
        f->PutFloat(fontheight);
        f->PutFloat(fontbaseline);
        f->PutLong(numtextures);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

