tlDataChunk*
tlTextureFontChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Pure3D::Texture::TEXTURE:
        dch = new tlTextureChunk(&ch);
        break;
    case Pure3D::Font::TEXTURE_GLYPH_LIST:
        dch = new tlTextureGlyphListChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

