int tlTextureGlyphListChunk::sortPriority = -1;

tlTextureGlyphListChunk::tlTextureGlyphListChunk()
{
    Init();
}

tlTextureGlyphListChunk::tlTextureGlyphListChunk(const tlTextureGlyphListChunk& ch)
{
    Init();
    *this = ch;
}

tlTextureGlyphListChunk::~tlTextureGlyphListChunk()
{

    if(glyphs != NULL){
        delete[] glyphs;
    }
}

tlTextureGlyphListChunk::tlTextureGlyphListChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Font::TEXTURE_GLYPH_LIST);
    ident = Pure3D::Font::TEXTURE_GLYPH_LIST;

    tlFile* f = ch->GetFile();
    unsigned int i;

    numglyphs = f->GetLong();
    glyphs = new tlTextureGlyph[numglyphs];
    for(i = 0; i < numglyphs; i++)
    {
        glyphs[i].Read(f);
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Font::TEXTURE_GLYPH_LIST);
    }
}

void
tlTextureGlyphListChunk::Init()
{
    ident = Pure3D::Font::TEXTURE_GLYPH_LIST;
    numglyphs = 0;
    glyphs = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Font::TEXTURE_GLYPH_LIST);
    }
}

long 
tlTextureGlyphListChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( numglyphs );
    for(i = 0; i < (int)numglyphs; i++)
    {
        s += sizeof( glyphs[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlTextureGlyphListChunk&
tlTextureGlyphListChunk::operator=(const tlTextureGlyphListChunk& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    numglyphs = a.numglyphs;
    if(glyphs)
    {
        delete glyphs;
    }
    glyphs = new tlTextureGlyph[numglyphs];
    for( i = 0; i < numglyphs ; i++ )
    {
        glyphs[i] = a.glyphs[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlTextureGlyphListChunk::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlTextureGlyphListChunk* aptr = dynamic_cast<const tlTextureGlyphListChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(numglyphs == aptr->numglyphs))
    {
        return false;
    }
    for(i = 0; i < numglyphs; i++)
    {
        if(!(glyphs[i] == aptr->glyphs[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

