tlImageFontChunk::operator==(const tlDataChunk& a)
{

    const tlImageFontChunk* aptr = dynamic_cast<const tlImageFontChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(version == aptr->version))
    {
        return false;
    }
    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(fontsize == aptr->fontsize))
    {
        return false;
    }
    if(!(fontwidth == aptr->fontwidth))
    {
        return false;
    }
    if(!(fontheight == aptr->fontheight))
    {
        return false;
    }
    if(!(fontbaseline == aptr->fontbaseline))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

