// tlImageGlyphListChunk

int tlImageGlyphListChunk::sortPriority = -1;

tlImageGlyphListChunk::tlImageGlyphListChunk()
{
    Init();
}

tlImageGlyphListChunk::tlImageGlyphListChunk(const tlImageGlyphListChunk& ch)
{
    Init();
    *this = ch;
}

tlImageGlyphListChunk::~tlImageGlyphListChunk()
{

    if(glyphs != NULL){
        delete[] glyphs;
    }
}

tlImageGlyphListChunk::tlImageGlyphListChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Font::IMAGE_GLYPH_LIST);
    ident = Pure3D::Font::IMAGE_GLYPH_LIST;

    tlFile* f = ch->GetFile();
    unsigned int i;

    numglyphs = f->GetLong();
    glyphs = new tlImageGlyph[numglyphs];
    for(i = 0; i < numglyphs; i++)
    {
        glyphs[i].Read(f);
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Font::IMAGE_GLYPH_LIST);
    }
}

void
tlImageGlyphListChunk::Init()
{
    ident = Pure3D::Font::IMAGE_GLYPH_LIST;
    numglyphs = 0;
    glyphs = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Font::IMAGE_GLYPH_LIST);
    }
}

long 
tlImageGlyphListChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( numglyphs );
    for(i = 0; i < (int)numglyphs; i++)
    {
        s += sizeof( glyphs[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlImageGlyphListChunk&
tlImageGlyphListChunk::operator=(const tlImageGlyphListChunk& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    numglyphs = a.numglyphs;
    if(glyphs)
    {
        delete glyphs;
    }
    glyphs = new tlImageGlyph[numglyphs];
    for( i = 0; i < numglyphs ; i++ )
    {
        glyphs[i] = a.glyphs[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlImageGlyphListChunk::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlImageGlyphListChunk* aptr = dynamic_cast<const tlImageGlyphListChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(numglyphs == aptr->numglyphs))
    {
        return false;
    }
    for(i = 0; i < numglyphs; i++)
    {
        if(!(glyphs[i] == aptr->glyphs[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlImageGlyphListChunk::NameCompare(const tlDataChunk& a)
{

    // This chunk has no name, so we must compare the bits
    return operator==(a);
}


tlDataChunk*
tlImageGlyphListChunk::Create(tlReadChunk16* ch)
{
    tlDataChunk* dtCh = new tlImageGlyphListChunk(ch);
    return dtCh;
}

void
tlImageGlyphListChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

    unsigned int i;
        f->PutLong(numglyphs);
    for(i = 0; i < numglyphs ; i++)
    {
        glyphs[i].Write(f);
    }

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlImageGlyphListChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{
    unsigned int i;

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlImageGlyphListChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  NumGlyphs = %ld\n",indent,"",numglyphs);
    printf("%*s  Glyphs:\n",indent,"");
    for( i=0; i < numglyphs; i++)
    {
         glyphs[i].Print(i, indent + 4);
    }

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlImageGlyphListChunk::PrintFormatted(int indent)
{
    unsigned int i;
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  int   %12ld # NumGlyphs\n",indent,"",numglyphs);
    printf("%*s  # Glyphs   \n",indent,""); 
    for( i=0; i < numglyphs; i++)
    {
         glyphs[i].PrintFormatted(i,indent+4);
    }
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

