bool 
tlImageGlyphListChunk::SetFieldValue(int fieldIndex, const char* new_val)
{
    switch(fieldIndex)
    {
        case 0:
        {
            char* end_ptr;
            unsigned long tmp;
            tmp = (unsigned long)strtoul(new_val, &end_ptr, 0);
            if (*end_ptr == 0)
            {
                numglyphs = tmp;
                return true;
            }
            return false;
        }
        case 1:
            return false;
        default:
            return false;
    }
}

